// ============================================================================
// In-process subagent runner
// ============================================================================

interface SubagentContext {
	authStorage?: AuthStorage;
	model?: any; // Parent's current model
}

async function runSubagent(
	specialist: Specialist,
	task: string,
	cwd: string,
	parentCtx?: SubagentContext,
	signal?: AbortSignal,
): Promise<{ output: string; turns: number }> {
	// Use parent's auth storage if available, otherwise create empty
	const authStorage = parentCtx?.authStorage ?? AuthStorage.create();
	const modelRegistry = ModelRegistry.inMemory(authStorage);

	// Resolve model: specialist.custom > parent's model
	let model;
	if (specialist.model) {
		// Specialist has custom model specified
		const [provider, id] = specialist.model.split("/");
		model = getModel(provider, id);
	} else if (parentCtx?.model) {
		// Inherit parent's model
		model = parentCtx.model;
	}

