### 1. Pi Extensions `registerTool` API

```typescript
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";

pi.registerTool({
  name: "my_tool",                    // Unique tool name (LLM calls this)
  label: "My Tool",                   // Display name in TUI
  description: "What it does",        // Shown to LLM
  promptSnippet: "One-liner for system prompt 'Available tools' section",
  promptGuidelines: ["Use my_tool when the user asks to browse the web."],
  parameters: Type.Object({           // TypeBox schema for LLM function calling
    url: Type.String({ description: "URL to visit" }),
  }),
  async execute(toolCallId, params, signal, onUpdate, ctx) {
    // signal: AbortSignal — check signal?.aborted for cancellation
    // onUpdate: stream partial progress → onUpdate({ content: [...], details: {...} })
    // ctx: ExtensionContext (cwd, sessionManager, model, etc.)

    // Must truncate large output. Use truncateHead/truncateTail from pi-coding-agent.

    return {
      content: [{ type: "text", text: "Result text for LLM" }],
      details: { /* structured data for rendering/state */ },
      terminate: true, // optional: skip follow-up LLM call
    };
  },
  // Optional: custom TUI rendering
  renderCall(args, theme, context) { /* return Component */ },
  renderResult(result, options, theme, context) { /* return Component */ },
});
```

**Key rules:**
- `parameters` uses TypeBox (`Type.Object`, `Type.String`, `Type.Optional`, `StringEnum` from `@earendil-works/pi-ai`)
- **Throw** errors to signal failure (sets `isError: true`); never return error state
- Tools MUST truncate output (~50KB / 2000 lines) using `truncateHead`/`truncateTail`
- `promptGuidelines` bullets must name the tool explicitly ("Use `web_browse` when..." not "Use this tool when...")
- Tools can be registered at load time or dynamically in `session_start` / command handlers
- `pi.setActiveTools([...])` to enable/disable tools at runtime

---

### 2. CloakBrowser JavaScript API (Playwright)

**Install:** `npm install cloakbrowser`

**Key functions:**

```javascript
import { launch, launchContext, launchPersistentContext } from 'cloakbrowser';

// Launch browser (returns standard Playwright Browser)
const browser = await launch({
  headless: true,
  proxy: 'http://user:pass@proxy:8080',  // HTTP or SOCKS5
  args: ['--fingerprint=42069'],
  timezone: 'America/New_York',
  locale: 'en-US',
  humanize: true,           // human-like mouse/keyboard/scroll
  humanPreset: 'careful',   // slower, more deliberate
});

// Convenience: browser + context in one call
const context = await launchContext({
  userAgent: 'Custom UA',
  viewport: { width: 1920, height: 1080 },
});
const page = await context.newPage();

// Persistent profile (cookies/localStorage survive restarts)
const ctx = await launchPersistentContext({
  userDataDir: './chrome-profile',
  headless: false,
});
```

**Navigation & content (standard Playwright API):**

```javascript
const page = await browser.newPage();
await page.goto('https://example.com', { waitUntil: 'networkidle' });

// Get page content
const title = await page.title();
const html = await page.content();
const text = await page.innerText('body');
const url = page.url();

// Interact
await page.click('button#submit');
await page.fill('input#email', 'user@example.com');
await page.type('input#search', 'query', { delay: 50 });
await page.selectOption('select#lang', 'en');
await page.keyboard.press('Enter');

// Extract data
const links = await page.$$eval('a', els => els.map(e => ({ text: e.textContent, href: e.href })));
const screenshot = await page.screenshot({ path: 'shot.png' });
const result = await page.evaluate(() => document.title);

// Wait
await page.waitForSelector('.content');
await page.waitForLoadState('networkidle');

// Cleanup
await browser.close();
```

**Utility functions:**

```javascript
import { ensureBinary, clearCache, binaryInfo } from 'cloakbrowser';
await ensureBinary();        // pre-download binary
console.log(binaryInfo());   // version, platform, installed status
```

---

### 3. Minimal Extension File Structure

**Single-file (simplest):**

```
~/.pi/agent/extensions/
└── web-browse.ts
```

```typescript
// ~/.pi/agent/extensions/web-browse.ts
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { truncateHead, DEFAULT_MAX_BYTES, DEFAULT_MAX_LINES } from "@earendil-works/pi-coding-agent";

export default function (pi: ExtensionAPI) {
  pi.registerTool({
    name: "web_browse",
    label: "Web Browse",
    description: "Browse a webpage and return its text content",
    promptSnippet: "Fetch and read a webpage URL",
    promptGuidelines: [
      "Use web_browse when the user asks to visit, read, or fetch a webpage."
    ],
    parameters: Type.Object({
      url: Type.String({ description: "URL to browse" }),
    }),
    async execute(toolCallId, params, signal, onUpdate, ctx) {
      const { launch } = await import("cloakbrowser");
      const browser = await launch({ headless: true });
      try {
        const page = await browser.newPage();
        await page.goto(params.url, { waitUntil: "domcontentloaded", signal });
        const text = await page.innerText("body");
        const truncation = truncateHead(text, {
          maxLines: DEFAULT_MAX_LINES,
          maxBytes: DEFAULT_MAX_BYTES,
        });
        return {
          content: [{ type: "text", text: truncation.content }],
          details: { url: params.url, title: await page.title() },
        };
      } finally {
        await browser.close();
      }
    },
  });
}
```

