### 3. Minimal extension file structure

**Simplest — single file:**
```
~/.pi/agent/extensions/
└── cloak-browser.ts
```

**With npm dependencies (e.g., `cloakbrowser` + `playwright-core`):**
```
~/.pi/agent/extensions/
└── cloak-browser/
    ├── package.json       # declares cloakbrowser, playwright-core deps
    ├── package-lock.json
    ├── node_modules/      # after npm install
    └── src/
        └── index.ts       # exports default function(pi: ExtensionAPI)
```

**`package.json` pattern (from `with-deps` example):**
```json
{
  "name": "pi-cloak-browser",
  "private": true,
  "version": "0.1.0",
  "type": "module",
  "pi": {
    "extensions": ["./src/index.ts"]
  },
  "dependencies": {
    "cloakbrowser": "^0.3.31",
    "playwright-core": "^1.52.0"
  }
}
```

**`src/index.ts` skeleton:**
```typescript
import type { ExtensionAPI } from "@earendil-works/pi-coding-agent";
import { Type } from "typebox";
import { launch } from "cloakbrowser";

export default function (pi: ExtensionAPI) {
  let browser: any = null;

  pi.registerTool({
    name: "browse",
    label: "Browse Web",
    description: "Launch a stealth browser and fetch page content from a URL",
    parameters: Type.Object({
      url: Type.String({ description: "URL to visit" }),
    }),
    async execute(_toolCallId, params, _signal, _onUpdate) {
      _onUpdate?.({ content: [{ type: "text", text: `Navigating to ${params.url}...` }] });

      browser = await launch({ headless: true });
      const page = await browser.newPage();
      await page.goto(params.url);
      const title = await page.title();
      const content = await page.locator("body").textContent();
      await browser.close();
      browser = null;

      return {
        content: [{ type: "text", text: `Title: ${title}\n\n${content}` }],
        details: { url: params.url },
      };
    },
  });

  // Clean up on shutdown
  pi.on("session_shutdown", async () => {
    if (browser) {
      await browser.close();
      browser = null;
    }
  });
}
```

**Placement options:**
| Location | Scope |
|----------|-------|
| `~/.pi/agent/extensions/cloak-browser.ts` | Global (all projects) |
| `~/.pi/agent/extensions/cloak-browser/index.ts` | Global (subdirectory) |
| `.pi/extensions/cloak-browser.ts` | Project-local |

**Test with:**
```bash
pi -e ./cloak-browser.ts
```

