let output = "";
let turns = 0;
const recentLines: string[] = [];
const MAX_RECENT = 4;

const appendRecent = (line: string) => {
	recentLines.push(line);
	if (recentLines.length > MAX_RECENT) recentLines.shift();
};

const getRecentDisplay = () => recentLines.join("\n");

const unsubscribe = session.subscribe((event) => {
	if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
		output += event.assistantMessageEvent.delta;
		// Track lines as they complete
		const text = event.assistantMessageEvent.delta;
		if (text.includes("\n")) {
			const lines = text.split("\n");
			for (const line of lines) {
				if (line.trim()) appendRecent(line.trim());
			}
		} else if (text.trim()) {
			appendRecent(text.trim());
		}
	}
	if (event.type === "message_end" && event.message?.role === "assistant") {
		turns++;
		onUpdate?.({
			content: [{ type: "text", text: `[${specialist.name}] turn ${turns} done\n\nRecent:\n${getRecentDisplay()}` }],
			details: { specialist: specialist.name, status: "running", turns },
		});
	}
	if (event.type === "tool_call") {
		onUpdate?.({
			content: [{ type: "text", text: `[${specialist.name}] using ${event.toolName}\n\nRecent:\n${getRecentDisplay()}` }],
			details: { specialist: specialist.name, status: "running", tool: event.toolName },
		});
	}
});

