function renderActivityFeed(name: string, state: ActivityFeedState): string {
	const lines: string[] = [];
	const p = (text: string) => `[${name}] ${text}`;

	if (state.goal) {
		lines.push(p(`Goal: ${state.goal}`));
		lines.push(p(""));
	}

	// If no steps yet, show starting
	if (state.steps.length === 0) {
		lines.push(p("→ Starting..."));
		return lines.join("\n");
	}

	const MAX_VISIBLE_SUBSTEPS = 2;

	for (let i = 0; i < state.steps.length; i++) {
		const step = state.steps[i];
		const isCurrent = i === state.currentStep;
		const isPending = !step.completed && !isCurrent;

		if (step.completed) {
			// Collapsed: show count
			const count = step.substeps.length;
			const suffix = count > 0 ? ` (${count} items)` : "";
			lines.push(p(`✓ ${step.label}${suffix}`));
		} else if (isCurrent) {
			// Expanded: show step + recent substeps
			lines.push(p(`→ ${step.label}`));
			const substeps = step.substeps;
			if (substeps.length > MAX_VISIBLE_SUBSTEPS) {
				// Show collapsed count + last N
				const hidden = substeps.length - MAX_VISIBLE_SUBSTEPS;
				lines.push(p(`    ✓ (+${hidden} more)`));
				for (const sub of substeps.slice(-MAX_VISIBLE_SUBSTEPS)) {
					lines.push(p(`    ${sub.completed ? "✓" : "→"} ${sub.label}`));
				}
			} else {
				for (const sub of substeps) {
					lines.push(p(`    ${sub.completed ? "✓" : "→"} ${sub.label}`));
				}
				if (substeps.length === 0) {
					lines.push(p("    ○ (pending)"));
				}
			}
		} else if (isPending) {
			lines.push(p(`○ ${step.label}`));
		}
	}

	return lines.join("\n");
}

