function renderActivityFeed(name: string, state: ActivityFeedState): string {
	const lines: string[] = [];

	// If no steps yet, show starting
	if (state.steps.length === 0) {
		lines.push(`  ⠋ Starting...`);
		return lines.join("\n");
	}

	// Find current step and show its subtasks
	if (state.currentStep >= 0 && state.currentStep < state.steps.length) {
		const currentStep = state.steps[state.currentStep];
		const substeps = currentStep.substeps;

		if (substeps.length === 0) {
			// No substeps yet - show step name
			lines.push(`  ⠋ ${currentStep.label}...`);
		} else {
			// Show substeps in chronological order (oldest first)
			for (const sub of substeps) {
				if (sub.completed) {
					lines.push(`  ✓ ${sub.label}`);
				} else {
					lines.push(`  ⠋ ${sub.label}...`);
				}
			}
		}
	} else if (state.steps.every((s) => s.completed)) {
		// All done
		lines.push(`  ✓ Done`);
	}

	return lines.join("\n");
}

