/**
 * Compress subagent output for token savings.
 * 
 * Cache-safe: compression happens BEFORE output enters parent context.
 * This is similar to token-saver's approach but applied to subagent output.
 * 
 * Compression layers:
 *   1. ANSI strip — remove color codes
 *   2. Blank collapse — remove redundant blank lines
 *   3. Line limit — cap at MAX_OUTPUT_LINES
 *   4. Redundant prefix removal — strip "Here's...", "Sure..." etc.
 *   5. Whitespace normalization — collapse multiple spaces
 */
const MAX_OUTPUT_LINES = 200;

function compressOutput(output: string): string {
	let result = output;

	// 1. Strip ANSI color codes
	result = result.replace(ANSI_RE, "");

	// 2. Collapse triple+ blank lines
	result = result.replace(/\n{3,}/g, "\n\n");

	// 3. Remove redundant prefixes (token-saver style)
	const redundantPrefixes = [
		/^Here'?s (what I found|the|a|an|my|the result|a summary)[^.]*:\s*/im,
		/^Sure[!.]?\s*/im,
		/^Certainly[!.]?\s*/im,
		/^Of course[!.]?\s*/im,
		/^I'?d be happy to help[^.]*\.\s*/im,
		/^Let me (help you|check|look|investigate|find|search)[^.]*\.\s*/im,
		/^Great question[!.]?\s*/im,
	];
	for (const prefix of redundantPrefixes) {
		result = result.replace(prefix, "");
	}

	// 4. Normalize whitespace (collapse multiple spaces, keep newlines)
	result = result.replace(/[^\S\n]+/g, " ");

	// 5. Line limit
	const lines = result.split("\n");
	if (lines.length > MAX_OUTPUT_LINES) {
		const kept = lines.slice(0, MAX_OUTPUT_LINES);
		result = kept.join("\n") + `\n[...${lines.length - MAX_OUTPUT_LINES} lines truncated]`;
	}

	// 6. Trim leading/trailing whitespace
	result = result.trim();

	return result;
}

